import { pushAgentSessionEvent } from "../agentSessionChannel.js";
import { getConfig, hasCredentials } from "../config.js";
export async function runPushActivity() {
    const args = process.argv.slice(2);
    const sessionId = args[0];
    const action = args[1];
    const displayName = args[2];
    if (!sessionId || !action || !displayName) {
        console.error("Usage: pushActivity <sessionId> <started|completed|failed> <displayName>");
        process.exit(1);
    }
    if (!["started", "completed", "failed"].includes(action)) {
        console.error("Action must be one of: started, completed, failed");
        process.exit(1);
    }
    if (!hasCredentials()) {
        console.error("Not authenticated.");
        process.exit(1);
    }
    const config = getConfig();
    if (!config.apiKey) {
        console.error("No API key configured.");
        process.exit(1);
    }
    await pushAgentSessionEvent({ serviceUrl: config.serviceUrl, apiKey: config.apiKey, sessionId }, {
        type: "agent:activity",
        data: { action, tool: "assistant", displayName },
    });
    process.exit(0);
}
